// COMPLETE, COMPILABLE C code
#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int main() {
    int N, k;
    scanf("%d %d", &N, &k);
    int numbers[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &numbers[i]);
    }
    int forward[N];
    forward[0] = 0;
    for (int i = 1; i < N; i++) {
        forward[i] = max(forward[i-1], forward[i-2] + numbers[i]);
    }
    int backward[N];
    backward[N-1] = 0;
    for (int i = N-2; i >= 0; i--) {
        backward[i] = max(backward[i+1], backward[i+2] + numbers[i]);
    }
    int max_score = 0;
    for (int i = k-1; i < N; i++) {
        max_score = max(max_score, forward[i] + backward[i]);
    }
    printf("%d\n", max_score);
    return 0;
}

